                  <p:cSld><p:spTree><p:sp>
                    <p:spPr><a:xfrm rot="10800000" flipV="1"><a:off x="914400" y="914400"/><a:ext cx="3657600" cy="914400"/></a:xfrm><a:prstGeom prst="rect"/></p:spPr>
