                <c:catAx><c:axId val="10"/><c:scaling><c:orientation val="minMax"/></c:scaling><c:axPos val="b"/><c:crossAx val="20"/><c:tickLblPos val="bogus"/></c:catAx>
                <c:valAx><c:axId val="20"/><c:scaling><c:min val="0"/><c:max val="5"/></c:scaling><c:axPos val="l"/><c:crossAx val="10"/></c:valAx>
              </c:plotArea></c:chart>
            </c:chartSpace>
            """) ?? throw new InvalidOperationException("Expected chart scene.");
        PptxSceneChartAxis categoryAxis = chart.Axes.First(axis => axis.AxisKind == PptxSceneChartAxisKind.Category);
        TestAssert.Equal(PptxSceneChartTickLabelPosition.Unknown, categoryAxis.TickLabelPositionKind);
        TestAssert.Equal("bogus", categoryAxis.TickLabelPosition);

        XNamespace c = "http://schemas.openxmlformats.org/drawingml/2006/chart";
        XElement mismatchedXmlFallback = XDocument.Parse("""
            <?xml version="1.0" encoding="UTF-8"?>
            <c:chartSpace xmlns:c="http://schemas.openxmlformats.org/drawingml/2006/chart">
              <c:chart><c:plotArea><c:catAx><c:tickLblPos val="none"/></c:catAx></c:plotArea></c:chart>
            </c:chartSpace>
            """).Descendants(c + "catAx").Single();
        System.Reflection.MethodInfo labelVisible = typeof(PptxRenderer).GetMethod(
            "IsSceneOrXmlChartAxisLabelVisible",
            System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Static) ?? throw new InvalidOperationException("Expected axis label visibility resolver.");
        object visible = labelVisible.Invoke(null, [categoryAxis, mismatchedXmlFallback]) ?? throw new InvalidOperationException("Expected resolved axis label visibility.");

        TestAssert.True((bool)visible, "Unknown scene-owned tickLblPos should resolve to the Office default nextTo/visible, not fall back to mismatched XML.");
    }

    public static void PptxChartMissingMajorTickMarkResolvesThroughExplicitDefault()
    {
        PptxSceneChart chart = BuildSingleChartScene("""
            <?xml version="1.0" encoding="UTF-8"?>
            <c:chartSpace xmlns:c="http://schemas.openxmlformats.org/drawingml/2006/chart">
              <c:chart><c:plotArea>
                <c:lineChart>
                  <c:ser><c:cat><c:strLit><c:pt idx="0"><c:v>A</c:v></c:pt></c:strLit></c:cat><c:val><c:numLit><c:pt idx="0"><c:v>2</c:v></c:pt></c:numLit></c:val></c:ser>
                  <c:axId val="10"/><c:axId val="20"/>
                </c:lineChart>
                <c:catAx><c:axId val="10"/><c:axPos val="b"/><c:crossAx val="20"/></c:catAx>
                <c:valAx><c:axId val="20"/><c:axPos val="l"/><c:crossAx val="10"/></c:valAx>
              </c:plotArea></c:chart>
            </c:chartSpace>
            """) ?? throw new InvalidOperationException("Expected chart scene.");
        PptxSceneChartAxis categoryAxis = chart.Axes.First(axis => axis.AxisKind == PptxSceneChartAxisKind.Category);
        TestAssert.Equal(PptxSceneChartAxisTickMark.Unknown, categoryAxis.MajorTickMarkKind);
        TestAssert.Equal(string.Empty, categoryAxis.MajorTickMark);

        System.Reflection.MethodInfo readMajorTickMark = typeof(PptxRenderer).GetMethod(
            "ReadSceneOrXmlChartAxisMajorTickMark",
            System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Static) ?? throw new InvalidOperationException("Expected chart major tick-mark resolver.");
        object tickMark = readMajorTickMark.Invoke(null, [categoryAxis, null]) ?? throw new InvalidOperationException("Expected resolved major tick mark.");

        TestAssert.Equal(PptxSceneChartAxisTickMark.None, (PptxSceneChartAxisTickMark)tickMark);
    }

    public static void PptxChartUnknownDisplayBlanksAsUsesSceneAuthoritativeDefault()
    {
        PptxSceneChart chart = BuildSingleChartScene("""
            <?xml version="1.0" encoding="UTF-8"?>
            <c:chartSpace xmlns:c="http://schemas.openxmlformats.org/drawingml/2006/chart">
              <c:chart><c:plotArea>
                <c:lineChart>
                  <c:ser><c:cat><c:strLit><c:pt idx="0"><c:v>A</c:v></c:pt></c:strLit></c:cat><c:val><c:numLit><c:pt idx="0"><c:v>2</c:v></c:pt></c:numLit></c:val></c:ser>
                </c:lineChart>
              </c:plotArea><c:dispBlanksAs val="bogus"/></c:chart>
            </c:chartSpace>
            """) ?? throw new InvalidOperationException("Expected chart scene.");
        TestAssert.Equal(PptxSceneChartDisplayBlanksAs.Unknown, chart.Options.DisplayBlanksAsKind);
        TestAssert.Equal("bogus", chart.Options.DisplayBlanksAs);

        XDocument mismatchedXmlFallback = XDocument.Parse("""
            <?xml version="1.0" encoding="UTF-8"?>
            <c:chartSpace xmlns:c="http://schemas.openxmlformats.org/drawingml/2006/chart">
              <c:chart><c:dispBlanksAs val="span"/></c:chart>
            </c:chartSpace>
            """);
        System.Reflection.MethodInfo readDisplayBlanksAs = typeof(PptxRenderer).GetMethod(
            "ReadSceneOrXmlChartDisplayBlanksAs",
            System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Static) ?? throw new InvalidOperationException("Expected display-blanks resolver.");
        object displayBlanksAs = readDisplayBlanksAs.Invoke(null, [chart, mismatchedXmlFallback]) ?? throw new InvalidOperationException("Expected resolved display-blanks value.");

        TestAssert.Equal(PptxSceneChartDisplayBlanksAs.Gap, (PptxSceneChartDisplayBlanksAs)displayBlanksAs);
    }

    public static void PptxSceneLineChartMarkerDefaultsUsePlotMarkerState()
    {
        PptxSceneChart? chart = BuildSingleChartScene("""
            <?xml version="1.0" encoding="UTF-8"?>
            <c:chartSpace xmlns:c="http://schemas.openxmlformats.org/drawingml/2006/chart">
              <c:chart><c:plotArea>
                <c:lineChart>
                  <c:marker val="1"/>
                  <c:ser><c:val><c:numLit><c:pt idx="0"><c:v>2</c:v></c:pt></c:numLit></c:val></c:ser>
                  <c:ser><c:marker><c:symbol val="plus"/><c:size val="9"/></c:marker><c:val><c:numLit><c:pt idx="0"><c:v>3</c:v></c:pt></c:numLit></c:val></c:ser>
                  <c:ser><c:val><c:numLit><c:pt idx="0"><c:v>4</c:v></c:pt></c:numLit></c:val></c:ser>
                  <c:ser><c:marker><c:spPr xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main"><a:solidFill><a:srgbClr val="4472C4"/></a:solidFill></c:spPr></c:marker><c:val><c:numLit><c:pt idx="0"><c:v>5</c:v></c:pt></c:numLit></c:val></c:ser>
                </c:lineChart>
              </c:plotArea></c:chart>
            </c:chartSpace>
            """);

        PptxSceneChartPlot plot = chart?.Plots[0] ?? throw new InvalidOperationException("Expected line-chart plot.");
        TestAssert.True(plot.MarkersEnabled == true, "Expected chart-level marker enablement to survive in the scene model.");
        TestAssert.Equal("1", plot.MarkersEnabledValue);
        TestAssert.True(plot.Series[0].Marker.IsDefined == false, "Expected an automatically enabled marker to remain distinct from series marker XML.");
        TestAssert.Equal("diamond", plot.Series[0].Marker.Symbol);
        TestAssert.Equal(7d, plot.Series[0].Marker.Size);
        TestAssert.True(plot.Series[1].Marker.IsDefined == true, "Expected explicit series marker XML to remain explicit.");
        TestAssert.Equal("plus", plot.Series[1].Marker.Symbol);
        TestAssert.Equal("9", plot.Series[1].Marker.SizeValue ?? string.Empty);
        TestAssert.True(plot.Series[2].Marker.IsDefined == false, "Expected missing sibling markers to stay missing even when their effective style is modeled.");
        TestAssert.Equal("triangle", plot.Series[2].Marker.Symbol);
        TestAssert.Equal(7d, plot.Series[2].Marker.Size);
        TestAssert.True(plot.Series[3].Marker.IsDefined == true, "Expected styled series marker XML to stay explicit.");
        TestAssert.Equal("x", plot.Series[3].Marker.Symbol);
        TestAssert.Equal(9d, plot.Series[3].Marker.Size);
    }

    public static void PptxChartMarkerStylesPreserveDefinitionState()
    {
        PptxSceneChart chart = BuildSingleChartScene("""
            <?xml version="1.0" encoding="UTF-8"?>
            <c:chartSpace xmlns:c="http://schemas.openxmlformats.org/drawingml/2006/chart">
              <c:chart><c:plotArea>
                <c:lineChart>
                  <c:marker val="1"/>
                  <c:ser><c:val><c:numLit><c:pt idx="0"><c:v>2</c:v></c:pt></c:numLit></c:val></c:ser>
                  <c:ser><c:marker><c:symbol val="plus"/><c:size val="9"/></c:marker><c:val><c:numLit><c:pt idx="0"><c:v>3</c:v></c:pt></c:numLit></c:val></c:ser>
                </c:lineChart>
              </c:plotArea></c:chart>
            </c:chartSpace>
            """) ?? throw new InvalidOperationException("Expected chart scene.");
        PptxSceneChartPlot plot = chart.Plots[0];

        XNamespace c = "http://schemas.openxmlformats.org/drawingml/2006/chart";
        XElement mismatchedXmlFallback = XDocument.Parse("""
            <?xml version="1.0" encoding="UTF-8"?>
            <c:chartSpace xmlns:c="http://schemas.openxmlformats.org/drawingml/2006/chart">
              <c:chart><c:plotArea><c:lineChart>
                <c:marker val="0"/>
                <c:ser><c:marker><c:symbol val="none"/><c:size val="4"/></c:marker></c:ser>
              </c:lineChart></c:plotArea></c:chart>
            </c:chartSpace>
            """).Descendants(c + "lineChart").Single();
        System.Reflection.MethodInfo readStyles = typeof(PptxRenderer).GetMethod(
            "ReadSceneOrXmlMarkerStyles",
            System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Static) ?? throw new InvalidOperationException("Expected marker-style resolver.");
        object[] sceneStyles = (((System.Collections.IEnumerable?)readStyles.Invoke(null, [plot, mismatchedXmlFallback, PptxTheme.Empty])) ?? throw new InvalidOperationException("Expected scene marker styles.")).Cast<object>().ToArray();
        TestAssert.Equal(2, sceneStyles.Length);
        TestAssert.Equal("diamond", ChartMarkerStyleSymbol(sceneStyles[0]));
        TestAssert.True(!ChartMarkerStyleIsDefined(sceneStyles[0]), "Expected auto line marker to remain distinct from explicit series marker XML.");
        TestAssert.Equal(string.Empty, ChartMarkerStyleSizeValue(sceneStyles[0]) ?? string.Empty);
        TestAssert.Equal(7d, ChartMarkerStyleSize(sceneStyles[0]));
        TestAssert.Equal("plus", ChartMarkerStyleSymbol(sceneStyles[1]));
        TestAssert.True(ChartMarkerStyleIsDefined(sceneStyles[1]), "Expected explicit series marker XML to remain explicit at the renderer option boundary.");
        TestAssert.Equal("9", ChartMarkerStyleSizeValue(sceneStyles[1]) ?? string.Empty);

        XElement xmlOnly = XDocument.Parse("""
            <?xml version="1.0" encoding="UTF-8"?>
            <c:chartSpace xmlns:c="http://schemas.openxmlformats.org/drawingml/2006/chart">
              <c:chart><c:plotArea><c:lineChart>
                <c:marker val="1"/>
                <c:ser/>
                <c:ser><c:marker><c:symbol val="square"/><c:size val="8"/></c:marker></c:ser>
              </c:lineChart></c:plotArea></c:chart>
            </c:chartSpace>
            """).Descendants(c + "lineChart").Single();
        object[] xmlStyles = (((System.Collections.IEnumerable?)readStyles.Invoke(null, [null, xmlOnly, PptxTheme.Empty])) ?? throw new InvalidOperationException("Expected XML marker styles.")).Cast<object>().ToArray();
        TestAssert.Equal(2, xmlStyles.Length);
        TestAssert.Equal("diamond", ChartMarkerStyleSymbol(xmlStyles[0]));
        TestAssert.True(!ChartMarkerStyleIsDefined(xmlStyles[0]), "Expected XML-only auto marker to remain distinct from explicit series marker XML.");
        TestAssert.Equal("square", ChartMarkerStyleSymbol(xmlStyles[1]));
        TestAssert.True(ChartMarkerStyleIsDefined(xmlStyles[1]), "Expected XML-only explicit marker to preserve definition state.");
        TestAssert.Equal("8", ChartMarkerStyleSizeValue(xmlStyles[1]) ?? string.Empty);
    }

